record.field:
today = datetime.date.today()
company_partners = []
for company_id in env['res.company'].search([('partner_id', '!=', False)]):
    company_partners.append(company_id.partner_id.id)
for rec in records:
    project_ids = env['project.project'].search([('company_id', '=', rec.id), ('partner_id', 'not in', company_partners), ('active', '=', True)])
    for project_id in project_ids:
        parent_id = project_id.partner_id.mapped('parent_id') or project_id.partner_id
        invoice_ids = parent_id.invoice_ids + parent_id.mapped('child_ids').invoice_ids
        not_paid_invoice_ids = invoice_ids.filtered(lambda move: move.state == 'posted' and move.move_type == 'out_invoice' and
                                 move.payment_state in ['not_paid', 'partial'] and move.invoice_date_due != False and
                                 move.company_id.id == rec.id and move.invoice_date_due < today)
        if not_paid_invoice_ids:
            project_id.compute_project_color_remaining_hours()
            for task_id in project_id.task_ids:
                task_id.compute_task_color()
partner_ids = env['res.partner'].search([('is_company', '=', True), ('x_studio_customer_of', '=', rec.id)])
for partner_id in partner_ids:
    not_paid_invoice_ids = partner_id.invoice_ids.filtered(lambda move: move.state == 'posted' and
                           move.move_type == 'out_invoice' and move.payment_state in ['not_paid', 'partial'] and
                           move.invoice_date_due != False and move.company_id.id == partner_id.x_studio_customer_of.id)
    if not_paid_invoice_ids:
        partner_id.compute_late_invoice_status()
